mapper.select:
SELECT *
FROM chat_rooms
WHERE room_id = #{roomId}
AND owner_id = #{ownerId}
AND partner_id = #{partnerId}
LIMIT 1

mapper.insert:
INSERT IGNORE INTO chat_room_members (
    chat_room_id,
    member_id
) VALUES (
    #{chatRoomId},
    #{memberId}
)

mapper.update:
UPDATE chat_room_members
SET is_hidden = 0,
    hidden_at = NULL,
    joined_at = NOW()
WHERE chat_room_id = #{chatRoomId}
AND member_id = #{memberId}

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM chat_room_members
    WHERE chat_room_id = #{chatRoomId}
    AND member_id = #{memberId}
    AND is_hidden = 1
)

mapper.update:
UPDATE chat_rooms
SET last_message_id = #{messageId},
    last_message_at = #{sentAt}
WHERE chat_room_id = #{chatRoomId}

UPDATE chat_room_members
SET last_read_message_id = (
        SELECT latest.message_id
        FROM (
            SELECT MAX(message_id) AS message_id
            FROM chat_messages
            WHERE chat_room_id = #{chatRoomId}
        ) latest
    ),
    last_read_at = NOW()
WHERE chat_room_id = #{chatRoomId}
AND member_id = #{memberId}

UPDATE chat_room_members
SET is_hidden = 1,
    hidden_at = NOW(),
    left_at = NOW()
WHERE chat_room_id = #{chatRoomId}
AND member_id = #{memberId}

UPDATE chat_room_members
SET notifications_enabled = #{notificationsEnabled}
WHERE chat_room_id = #{chatRoomId}
AND member_id = #{memberId}
